class Solution {
    public int maxFreq(String s, int maxLetters, int minSize, int maxSize) {
        int maxCount = 0;
        for (int size = minSize; size <= maxSize; size++) {
            Map<String, Integer> freqMap = new HashMap<>();
            for (int i = 0; i <= s.length() - size; i++) {
                String substr = s.substring(i, i + size);
                int uniqueChars = (int) substr.chars().distinct().count();
                if (uniqueChars <= maxLetters) {
                    freqMap.put(substr, freqMap.getOrDefault(substr, 0) + 1);
                    maxCount = Math.max(maxCount, freqMap.get(substr));
                }
            }
        }
        return maxCount;
    }
}
